+/**
+ * DLD Historical Backfill Script
+ * ================================
+ * One-shot script to import the last 24 months of DLD transaction data.
+ * Safe to re-run — already-imported months (>=100 records) are skipped.
+ *
+ * HOW TO RUN
+ * ----------
+ * Locally:
+ *   npm run dld-backfill
+ *   (requires .env file with MONGODB_URI set)
+ *
+ * On Render (SSH into the service instance):
+ *   cd /opt/render/project/src
+ *   npm run dld-backfill
+ *
+ * Cron / scheduling:
+ *   This is a one-shot backfill — do NOT run it on a schedule.
+ *   The daily incremental cron in dld-worker.ts handles ongoing updates.
+ */
+
+import "dotenv/config";
+import mongoose from "mongoose";
+import { connectDB } from "../src/lib/mongodb.js";
+import { importDateRange } from "../src/services/fetchers/dld-fetcher.js";
+import DldTransaction from "../src/models/DldTransaction.js";
+
+/** Minimum existing records that indicate a month is already fully imported. */
+const SKIP_THRESHOLD = 100;
+
+/** Number of months back from today to cover. */
+const BACKFILL_MONTHS = 24;
+
+function monthStart(year: number, month: number): Date {
+  return new Date(year, month, 1, 0, 0, 0, 0);
+}
+
+function monthEnd(year: number, month: number): Date {
+  // Day 0 of next month = last day of this month
+  return new Date(year, month + 1, 0, 23, 59, 59, 999);
+}
+
+async function main(): Promise<void> {
+  await connectDB();
+
+  const now = new Date();
+
+  // Build ordered list of (year, month) pairs from 24 months ago to current month
+  const months: Array<{ year: number; month: number }> = [];
+  for (let i = BACKFILL_MONTHS - 1; i >= 0; i--) {
+    const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
+    months.push({ year: d.getFullYear(), month: d.getMonth() });
+  }
+
+  console.log(`[dld-backfill] Starting backfill for ${months.length} months`);
+  console.log(`[dld-backfill] Range: ${months[0].year}-${String(months[0].month + 1).padStart(2, "0")} → ${months[months.length - 1].year}-${String(months[months.length - 1].month + 1).padStart(2, "0")}`);
+  console.log();
+
+  let totalMonthsProcessed = 0;
+  let totalMonthsSkipped = 0;
+  let totalRecordsImported = 0;
+
+  for (const { year, month } of months) {
+    const label = `${year}-${String(month + 1).padStart(2, "0")}`;
+    const from = monthStart(year, month);
+    const to = monthEnd(year, month);
+
+    // Check if this month is already sufficiently populated
+    const existing = await DldTransaction.countDocuments({
+      transactionDate: { $gte: from, $lte: to },
+    });
+
+    if (existing >= SKIP_THRESHOLD) {
+      console.log(`[dld-backfill] ${label}: skipped — already has ${existing} records`);
+      totalMonthsSkipped++;
+      continue;
+    }
+
+    try {
+      const imported = await importDateRange(from, to);
+      totalRecordsImported += imported;
+      totalMonthsProcessed++;
+      console.log(`[dld-backfill] ${label}: imported ${imported} new records (had ${existing} before)`);
+    } catch (err) {
+      console.error(`[dld-backfill] ${label}: ERROR — ${(err as Error).message}`);
+      // Continue with next month — don't abort the whole run
+    }
+  }
+
+  console.log();
+  console.log("======================================");
+  console.log(`[dld-backfill] Done.`);
+  console.log(`  Months processed : ${totalMonthsProcessed}`);
+  console.log(`  Months skipped   : ${totalMonthsSkipped}`);
+  console.log(`  Records imported : ${totalRecordsImported}`);
+  console.log("======================================");
+}
+
+main()
+  .catch((err) => {
+    console.error("[dld-backfill] Fatal error:", err);
+    process.exit(1);
+  })
+  .finally(() => {
+    mongoose.disconnect();
+  });
